INSERT INTO molecules (id, name, trade_names, class, clinical_axes, mechanisms, notes, side_effects, contraindications, routes, psychiatry_use, off_label_uses, on_label_uses, profile_symbols) VALUES 
('m1', 'Fluoxetina', '{"Prozac","Daforin"}', 'ISRS', '{"Antidepressivo"}', 'Inibição de SERT. Antagonismo fraco 5-HT2C.', 'Meia-vida muito longa, não requer desmame rigoroso.', '{"Insônia","Náusea inicial","Disfunção sexual","Cefaleia"}', '{"Uso concomitante com IMAO","Pimozida"}', '{"Oral","Cápsula","Comprimido","Solução Oral"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic"}'),
('m4', 'Sertralina', '{"Zoloft","Tolrest"}', 'ISRS', '{"Antidepressivo","Ansiolitico"}', 'Inibição de SERT. Fraca inibição DAT e ligação sigma-1.', 'Bom perfil de segurança cardíaca (post-IAM).', '{"Diarreia","Náusea","Disfunção sexual","Insônia","Boca seca"}', '{"Uso concomitante com IMAO"}', '{"Oral","Comprimido"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic","gold_standard"}'),
('m5', 'Paroxetina', '{"Aropax","Pondera"}', 'ISRS', '{"Antidepressivo","Ansiolitico"}', 'Inibição de SERT. Leve inibição NET e afinidade M1 (anticolinérgico).', 'Alta incidência de síndrome de abstinência/descontinuação.', '{"Ganho de peso","Sonolência","Disfunção sexual acentuada","Sudorese"}', '{"Uso concomitante com IMAO","Gravidez (Risco D)"}', '{"Oral","Comprimido"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic","anticholinergic"}'),
('m6', 'Escitalopram', '{"Lexapro"}', 'ISRS', '{"Antidepressivo","Ansiolitico"}', 'Inibição alostérica altamente seletiva de SERT.', 'Perfil bem tolerado. Risco de prolongamento QTc dependente da dose.', '{"Náusea","Ejaculação retardada","Fadiga","QTc prolongado"}', '{"Uso concomitante com IMAO","Prolongamento QTc basal"}', '{"Oral","Comprimido","Gotas"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic","gold_standard","cardiac_risk"}'),
('m7', 'Citalopram', '{"Cipramil"}', 'ISRS', '{"Antidepressivo","Ansiolitico"}', 'Inibição de SERT (mistura racêmica R/S). Fraco antagonismo H1.', 'Restrição de dose por risco documentado de prolongamento QTc.', '{"Prolongamento QTc","Náusea","Sudorese","Disfunção sexual"}', '{"Uso concomitante com IMAO","Uso concomitante com Pimozida","Braquicardia congênita"}', '{"Oral","Comprimido"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic","cardiac_risk"}'),
('m8', 'Fluvoxamina', '{"Luvox"}', 'ISRS', '{"Antidepressivo","Ansiolitico"}', 'Inibição de SERT e potente agonismo sigma-1.', 'Ouro no TOC. Interações medicamentosas extensas via inibição do CYP450.', '{"Náusea intensa","Sonolência","Astenia"}', '{"Uso concomitante com IMAO","Tizanidina","Ramelteon"}', '{"Oral","Comprimido"}', 'Na prática clínica psiquiátrica, é o tratamento de escolha (primeira linha) para depressão maior, ansiedade generalizada, pânico, fobia social e TOC. Atua primariamente aumentando a serotonina disponível para modulação do estado de humor e regulação emocional a longo prazo. É amplamente indicado pela boa segurança terapêutica, sobretudo quando o paciente apresenta humor depressivo crônico cruzado com sintomas ansiosos.', '[{"condition":"Ejaculação Precoce","evidence":"Alto","justification":"Aumenta o limiar de excitação temporal central, prolongando o tempo antes da ejaculação."},{"condition":"Síndrome do Intestino Irritável (SII)","evidence":"Moderado","justification":"Auxilia na neuromodulação do plexo entérico e na hiperalgesia visceral através do aumento da serotonina."},{"condition":"Sintomas Vasomotores da Menopausa","evidence":"Moderado","justification":"Pode reduzir fogachos e ondas de calor não responsivos à reposição hormonal."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de primeira escolha reconhecido por diretrizes internacionais pela excelente relação eficácia/tolerabilidade."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente controle crônico de preocupações excessivas, sintomas de tensão somática e estabilização de humor."},{"condition":"Transtorno de Pânico","line":"1ª Linha","evidence":"Robusto","justification":"Reduz a frequência e severidade dos ataques de pânico espontâneos, atenuando a ansiedade antecipatória."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Robusto","justification":"Requer doses mais elevadas do que na depressão (ex: Sertralina 200mg) para modular vias cortico-estriato-talâmicas."}]'::jsonb, '{"serotonergic"}'),
('m2', 'Haloperidol', '{"Haldol"}', 'Antipsicótico Típico', '{"Antipsicotico"}', 'Bloqueio potente D2.', 'Alto risco de sintomas extrapiramidais (SEP).', '{"Acatisia","Parkinsonismo","Distonia","Discinesia Tardia","Hiperprolactinemia"}', '{"Coma","Doença de Parkinson","Depressão severa do SNC"}', '{"Oral","Intramuscular (Decanoato)","Intravenoso (Agudo)"}', 'Reservados tipicamente para o controle agudo, fulminante, de episódios refratários de delírios, alucinações e agressividade psicótica primária. Por causa do extenso impacto no sistema dopaminérgico motor (sintomas extrapiramidais), deixou de ser primeira linha crônica na maioria das psicoses ambulatoriais silenciosas.', '[{"condition":"Delirium Refratário Hospitalar/UTI","evidence":"Alto","justification":"Haloperidol é usado para controle de emergência de agitação no doente crítico por ausência de impacto respiratório letal."},{"condition":"Soluços Severos Incoercíveis","evidence":"Anedótico","justification":"Mecanismo central exato não mapeado, mas o bloqueio dopaminérgico pode frear hiperreflexias do arco diafragmático."}]'::jsonb, '[{"condition":"Esquizofrenia / Surto Psicótico Agudo","line":"2ª Linha","evidence":"Robusto","justification":"Eficácia histórica inquestionável no bloqueio dopaminérgico mesolímbico, mas com alto risco de tremores extrapiramidais."},{"condition":"Agitação Psicomotora Grave (Emergência)","line":"1ª Linha","evidence":"Robusto","justification":"Efeito antipsicótico e sedativo imediato para contenção química segura de pacientes delirantes agressivos."}]'::jsonb, '{"dopaminergic","cardiac_risk"}'),
('m3', 'Aripiprazol', '{"Abilify","Aristab"}', 'Antipsicótico Atípico', '{"Antipsicotico","Estabilizador"}', 'Agonista parcial D2 e 5-HT1A, antagonista 5-HT2A.', 'Acatisia é comum em início de tratamento.', '{"Acatisia","Insônia","Inquietação","Cefaleia"}', '{}', '{"Oral","Comprimido","Intramuscular (Mensal)"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de escolha para controlar sintomas psicóticos positivos e negativos com menor risco de sintomas extrapiramidais."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."},{"condition":"Depressão Unipolar Refratária (Potencialização)","line":"Adjuvante","evidence":"Robusto","justification":"Usado em doses baixas para acelerar e potencializar a resposta clínica dos antidepressivos primários."}]'::jsonb, '{"dopaminergic","gold_standard","serotonergic"}'),
('m22', 'Clozapina', '{"Leponex"}', 'Antipsicótico Atípico', '{"Antipsicotico"}', 'Antagonista 5-HT2A e fraco D2. Antagonismo M1, H1 e Alpha-1.', 'Risco de agranulocitose requer hemograma rígido. Uso apenas em esquizofrenia refratária.', '{"Sialorreia","Sedação profunda","Ganho de peso extremo","Taquicardia","Constipação severa"}', '{"Mielossupressão prévia","Convulsões não controladas","Íleo paralítico"}', '{"Oral","Comprimido"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"Refratária","evidence":"Padrão-Ouro","justification":"Tratamento padrão-ouro absoluto para esquizofrenia resistente a múltiplos antipsicóticos. Reduz tendências suicidas."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."}]'::jsonb, '{"dopaminergic","antihistaminic","metabolic_risk","gold_standard","anticholinergic"}'),
('m23', 'Quetiapina', '{"Seroquel"}', 'Antipsicótico Atípico', '{"Antipsicotico","Estabilizador"}', 'Antagonismo H1 e 5-HT2A, com fraco bloqueio D2 transiente.', 'Efeito altamente sedativo. Metabólito norquetiapina atua na rede noradrenérgica.', '{"Sedação","Ganho de peso","Hipotensão ortostática","Boca seca"}', '{"Prolongamento QTc severo"}', '{"Oral","Comprimido","Comprimido de Liberação Prolongada (XR)"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de escolha para controlar sintomas psicóticos positivos e negativos com menor risco de sintomas extrapiramidais."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."},{"condition":"Depressão Unipolar Refratária (Potencialização)","line":"Adjuvante","evidence":"Robusto","justification":"Usado em doses baixas para acelerar e potencializar a resposta clínica dos antidepressivos primários."},{"condition":"Depressão Bipolar","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Um dos poucos medicamentos aprovados em monoterapia com alta eficácia para a fase depressiva no transtorno bipolar."}]'::jsonb, '{"dopaminergic","antihistaminic","metabolic_risk"}'),
('m24', 'Risperidona', '{"Risperdal"}', 'Antipsicótico Atípico', '{"Antipsicotico"}', 'Antagonista potente D2 e 5-HT2A.', 'Dentre os atípicos, tem alto risco de hiperprolactinemia e SEP dose-dependente.', '{"Hiperprolactinemia","Galactorreia","Sedação","Aumento de peso","Sintomas Extrapiramidais"}', '{}', '{"Oral","Comprimido","Gotas","Intramuscular (Depot)"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de escolha para controlar sintomas psicóticos positivos e negativos com menor risco de sintomas extrapiramidais."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."}]'::jsonb, '{"dopaminergic"}'),
('m25', 'Olanzapina', '{"Zyprexa"}', 'Antipsicótico Atípico', '{"Antipsicotico","Estabilizador"}', 'Amplo perfil antagonista em múltiplos receptores (D2, 5-HT2A, H1, M1).', 'Elevado impacto metabólico (ganho de peso, hiperglicemia e dislipidemia).', '{"Ganho de peso drástico","Síndrome metabólica","Sedação","Boca seca"}', '{"Risco de glaucoma de ângulo fechado"}', '{"Oral","Comprimido","Comprimido Orodispersível"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de escolha para controlar sintomas psicóticos positivos e negativos com menor risco de sintomas extrapiramidais."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."}]'::jsonb, '{"dopaminergic","antihistaminic","metabolic_risk","gold_standard"}'),
('m26', 'Ziprasidona', '{"Geodon"}', 'Antipsicótico Atípico', '{"Antipsicotico"}', 'Antagonismo 5-HT2A/D2, além de forte ação como inibidor de reuptake 5-HT/NE.', 'Deve obrigatoriamente ser tomada com pelo menos 500 calorias. Pode alongar o QTc.', '{"Prolongamento QTc","Ondas de calor","Somnolência"}', '{"Histórico de prolongamento QTc","Idosos com psicose relacionada à demência"}', '{"Oral","Capsula"}', 'Essencialmente desenvolvidos para o tratamento de espectros esquizofreniformes e crises do transtorno bipolar. Contudo, seu principal papel tem evoluído para o uso como adjuvante impulsionador na depressão maior refratária de difícil tratamento (como potencializador do antidepressivo primário). Recomendados também para acalmar quadros graves de agitação e severa impulsividade.', '[{"condition":"Insônia Primária Refratária","evidence":"Moderado","justification":"Extremo poder anticolinérgico/anti-histamínico gera sedação química (Quetiapina é amplamente abusada nesse fim, com ressalvas metabólicas graves)."},{"condition":"Transtorno da Personalidade Borderline (TPB)","evidence":"Baixo","justification":"Utilizado em baixas dosagens para atenuar a instabilidade afetiva explosiva e pseudo-sintomas psicóticos passageiros."},{"condition":"Agitação em Demências","evidence":"Moderado","justification":"Último recurso pra descontrole comportamental grave.","notes":"Nota: O uso na demência porta ''Black Box Warning'' para mortalidade cardiovascular idosa."}]'::jsonb, '[{"condition":"Esquizofrenia e Quadros Psicóticos","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de escolha para controlar sintomas psicóticos positivos e negativos com menor risco de sintomas extrapiramidais."},{"condition":"Transtorno Bipolar (Mania Aguda)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Rápida desaceleração psicomotora, redução da euforia ideativa e reestabelecimento do sono em episódios maníacos."}]'::jsonb, '{"dopaminergic"}'),
('m9', 'Venlafaxina', '{"Effexor","Efexor XR"}', 'ISRSN', '{"Antidepressivo","Ansiolitico"}', 'Inibe SERT em baixas doses; adição de inibição NET em doses mais altas.', 'Pode induzir elevação sustentada da pressão arterial (dose-dependente).', '{}', '{}', '{}', 'Tratamento de primeira linha para depressão maior estrutural, sendo especialmente útil em pacientes apáticos, sem iniciativa ou com lentificação psicomotora, onde a inibição potente paralela da noradrenalina ajuda a ''energizar'' o humor. Utilizado igualmente em quadros ansiosos severos crônicos.', '[{"condition":"Dor Crônica Neuropática / Dor Lombar","evidence":"Alto","justification":"A ação da serotonina juntamente com a noradrenalina reforça ativamente as vias inibitórias descendentes da dor na medula."},{"condition":"Fibromialgia","evidence":"Alto","justification":"Suprime de maneira consistente a hipersensibilidade periférica e alivia o binômio dor-depressão inerente ao quadro."},{"condition":"TDAH em adultos","evidence":"Anedótico","justification":"Pode proporcionar aumento tímido da cognição via atividade da noradrenalina cortical, caso estimulantes clássicos sejam proibitivos."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente indicação para quadros depressivos severos, com apatia intensa, fadiga física ou lentificação motora."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"A inibição da recaptação de noradrenalina em doses médias a altas estabiliza as vias de alerta límbicas a longo prazo."}]'::jsonb, '{"serotonergic","noradrenergic","gold_standard"}'),
('m10', 'Desvenlafaxina', '{"Pristiq"}', 'ISRSN', '{"Antidepressivo"}', 'Metabólito ativo direto (O-desmetilvenlafaxina). Inibe SERT e NET.', 'Eficácia previsível independente da metabolização do CYP2D6.', '{"Náusea","Tontura","Hiperidrose","Boca seca"}', '{"Uso concomitante com IMAO"}', '{"Oral","Comprimido de Liberação Prolongada"}', 'Tratamento de primeira linha para depressão maior estrutural, sendo especialmente útil em pacientes apáticos, sem iniciativa ou com lentificação psicomotora, onde a inibição potente paralela da noradrenalina ajuda a ''energizar'' o humor. Utilizado igualmente em quadros ansiosos severos crônicos.', '[{"condition":"Dor Crônica Neuropática / Dor Lombar","evidence":"Alto","justification":"A ação da serotonina juntamente com a noradrenalina reforça ativamente as vias inibitórias descendentes da dor na medula."},{"condition":"Fibromialgia","evidence":"Alto","justification":"Suprime de maneira consistente a hipersensibilidade periférica e alivia o binômio dor-depressão inerente ao quadro."},{"condition":"TDAH em adultos","evidence":"Anedótico","justification":"Pode proporcionar aumento tímido da cognição via atividade da noradrenalina cortical, caso estimulantes clássicos sejam proibitivos."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente indicação para quadros depressivos severos, com apatia intensa, fadiga física ou lentificação motora."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"A inibição da recaptação de noradrenalina em doses médias a altas estabiliza as vias de alerta límbicas a longo prazo."}]'::jsonb, '{"serotonergic","noradrenergic","gold_standard"}'),
('m11', 'Duloxetina', '{"Cymbalta","Velija"}', 'ISRSN', '{"Antidepressivo","Ansiolitico"}', 'Inibição de SERT e NET equilibrada em todas as doses.', 'Eficácia validada para fibromialgia, neuropatias pélvicas e dor lombar crônica.', '{"Náusea","Boca seca","Somnolência","Constipação"}', '{"Uso concomitante com IMAO","Insuficiência Hepática e/ou Renal (CrCl < 30)"}', '{"Oral","Cápsula com grânulos gastroresistentes"}', 'Tratamento de primeira linha para depressão maior estrutural, sendo especialmente útil em pacientes apáticos, sem iniciativa ou com lentificação psicomotora, onde a inibição potente paralela da noradrenalina ajuda a ''energizar'' o humor. Utilizado igualmente em quadros ansiosos severos crônicos.', '[{"condition":"Dor Crônica Neuropática / Dor Lombar","evidence":"Alto","justification":"A ação da serotonina juntamente com a noradrenalina reforça ativamente as vias inibitórias descendentes da dor na medula."},{"condition":"Fibromialgia","evidence":"Alto","justification":"Suprime de maneira consistente a hipersensibilidade periférica e alivia o binômio dor-depressão inerente ao quadro."},{"condition":"TDAH em adultos","evidence":"Anedótico","justification":"Pode proporcionar aumento tímido da cognição via atividade da noradrenalina cortical, caso estimulantes clássicos sejam proibitivos."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente indicação para quadros depressivos severos, com apatia intensa, fadiga física ou lentificação motora."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"A inibição da recaptação de noradrenalina em doses médias a altas estabiliza as vias de alerta límbicas a longo prazo."},{"condition":"Dor Neuropática Diabética / Fibromialgia","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Ativação potente das vias serotoninérgicas e noradrenérgicas descendentes na medula, inibindo sinais aferentes de dor."}]'::jsonb, '{"serotonergic","noradrenergic","gold_standard"}'),
('m12', 'Milnaciprana', '{"Ixel","Savella"}', 'ISRSN', '{"Antidepressivo"}', 'Afinidade de bloqueio levemente maior em NET comparada a SERT.', 'Maior uso em fibromialgia (Américas) e síndromes crônicas não-psiquiátricas.', '{"Náusea","Cefaleia","Palpitações","Constipação"}', '{"Uso concomitante com IMAO"}', '{"Oral","Comprimido"}', 'Tratamento de primeira linha para depressão maior estrutural, sendo especialmente útil em pacientes apáticos, sem iniciativa ou com lentificação psicomotora, onde a inibição potente paralela da noradrenalina ajuda a ''energizar'' o humor. Utilizado igualmente em quadros ansiosos severos crônicos.', '[{"condition":"Dor Crônica Neuropática / Dor Lombar","evidence":"Alto","justification":"A ação da serotonina juntamente com a noradrenalina reforça ativamente as vias inibitórias descendentes da dor na medula."},{"condition":"Fibromialgia","evidence":"Alto","justification":"Suprime de maneira consistente a hipersensibilidade periférica e alivia o binômio dor-depressão inerente ao quadro."},{"condition":"TDAH em adultos","evidence":"Anedótico","justification":"Pode proporcionar aumento tímido da cognição via atividade da noradrenalina cortical, caso estimulantes clássicos sejam proibitivos."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente indicação para quadros depressivos severos, com apatia intensa, fadiga física ou lentificação motora."},{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"A inibição da recaptação de noradrenalina em doses médias a altas estabiliza as vias de alerta límbicas a longo prazo."}]'::jsonb, '{"serotonergic","noradrenergic"}'),
('m13', 'Amitriptilina', '{"Tryptanol"}', 'Tricíclico', '{"Antidepressivo"}', 'Bloqueio SERT/NET. Forte bloqueio H1, M1 e alfa-1.', 'Letal em overdose. Extensão QTc. Risco arritmico alto.', '{"Retenção urinária","Constipação extrema","Sedação profunda","Visão turva","Hipotensão ortostática"}', '{"Recuperação aguda de infarto do miocárdio","Uso de IMAO","Glaucoma de ângulo fechado"}', '{"Oral","Comprimido"}', 'Considerados como opção robusta de segunda, terceira ou quarta linha nos fluxogramas de depressões unipolares difíceis de tratar ou TOCs graves. São os representantes mais antigos de agentes monoaminérgicos e ainda carregam uma das eficácias brutas mais consistentes na psiquiatria, mas são tolhidos frequentemente pelo perfil tóxico de efeitos colaterais cardíacos e anticolinérgicos.', '[{"condition":"Profilaxia de Enxaqueca","evidence":"Alto","justification":"A ação crônica multifatorial estabiliza os limiares vasculares neurogênicos da dor cefálica contínua (ex: Amitriptilina)."},{"condition":"Enurese Noturna (Infantil / Adulta)","evidence":"Moderado","justification":"A grande afinidade anticolinérgica (M1) deprime a contração tônica da bexiga noturna."},{"condition":"Neuralgia do Trigêmeo e Herpes","evidence":"Alto","justification":"Modulam efetivamente os impulsos neurais somatossensoriais hiperativos não-responsivos a AINEs."}]'::jsonb, '[{"condition":"Depressão Maior Refratária","line":"3ª Linha","evidence":"Robusto","justification":"A eficácia crua é espetacular, mas seu uso é relegado para linhas tardias devido à alta toxicidade e intolerabilidade dos efeitos colaterais."},{"condition":"Enxaqueca e Dores Neuropáticas","line":"1ª Linha","evidence":"Robusto","justification":"Ação de reforço de vias de controle de dor independente do humor. Amplamente usada na neurologia em doses baixas."}]'::jsonb, '{"serotonergic","noradrenergic","anticholinergic","antihistaminic","cardiac_risk"}'),
('m14', 'Imipramina', '{"Tofranil"}', 'Tricíclico', '{"Antidepressivo"}', 'Inibe primariamente SERT e NET. Perfil off-target anticolinérgico.', 'Primeiro TCA. Foi muito usado para enurese infantil e dor neuropática.', '{"Taquicardia","Inquietação","Boca seca","Hipotensão"}', '{"Uso concomitante com IMAO","Recuperação aguda pós-IAM"}', '{"Oral","Grágea"}', 'Considerados como opção robusta de segunda, terceira ou quarta linha nos fluxogramas de depressões unipolares difíceis de tratar ou TOCs graves. São os representantes mais antigos de agentes monoaminérgicos e ainda carregam uma das eficácias brutas mais consistentes na psiquiatria, mas são tolhidos frequentemente pelo perfil tóxico de efeitos colaterais cardíacos e anticolinérgicos.', '[{"condition":"Profilaxia de Enxaqueca","evidence":"Alto","justification":"A ação crônica multifatorial estabiliza os limiares vasculares neurogênicos da dor cefálica contínua (ex: Amitriptilina)."},{"condition":"Enurese Noturna (Infantil / Adulta)","evidence":"Moderado","justification":"A grande afinidade anticolinérgica (M1) deprime a contração tônica da bexiga noturna."},{"condition":"Neuralgia do Trigêmeo e Herpes","evidence":"Alto","justification":"Modulam efetivamente os impulsos neurais somatossensoriais hiperativos não-responsivos a AINEs."}]'::jsonb, '[{"condition":"Depressão Maior Refratária","line":"3ª Linha","evidence":"Robusto","justification":"A eficácia crua é espetacular, mas seu uso é relegado para linhas tardias devido à alta toxicidade e intolerabilidade dos efeitos colaterais."}]'::jsonb, '{"serotonergic","noradrenergic","anticholinergic","antihistaminic"}'),
('m15', 'Clomipramina', '{"Anafranil"}', 'Tricíclico', '{"Antidepressivo"}', 'Inibição de SERT muito intensa.', 'Ainda considerado padrão de grande eficácia no Transtorno Obsessivo Compulsivo.', '{"Tremor","Boca seca","Ganho de peso","Disfunção sexual extrema","Convulsões (dose-dependente)"}', '{"IAM recente","Risco alto de convulsões","Uso concomitante com IMAO"}', '{"Oral","Comprimido"}', 'Considerados como opção robusta de segunda, terceira ou quarta linha nos fluxogramas de depressões unipolares difíceis de tratar ou TOCs graves. São os representantes mais antigos de agentes monoaminérgicos e ainda carregam uma das eficácias brutas mais consistentes na psiquiatria, mas são tolhidos frequentemente pelo perfil tóxico de efeitos colaterais cardíacos e anticolinérgicos.', '[{"condition":"Profilaxia de Enxaqueca","evidence":"Alto","justification":"A ação crônica multifatorial estabiliza os limiares vasculares neurogênicos da dor cefálica contínua (ex: Amitriptilina)."},{"condition":"Enurese Noturna (Infantil / Adulta)","evidence":"Moderado","justification":"A grande afinidade anticolinérgica (M1) deprime a contração tônica da bexiga noturna."},{"condition":"Neuralgia do Trigêmeo e Herpes","evidence":"Alto","justification":"Modulam efetivamente os impulsos neurais somatossensoriais hiperativos não-responsivos a AINEs."}]'::jsonb, '[{"condition":"Depressão Maior Refratária","line":"3ª Linha","evidence":"Robusto","justification":"A eficácia crua é espetacular, mas seu uso é relegado para linhas tardias devido à alta toxicidade e intolerabilidade dos efeitos colaterais."},{"condition":"Transtorno Obsessivo-Compulsivo (TOC)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Único antidepressivo não-ISRS com eficácia comprovada equivalente ou superior no TOC pela sua avassaladora potência serotoninérgica."}]'::jsonb, '{"serotonergic","noradrenergic","anticholinergic","antihistaminic","cardiac_risk","gold_standard"}'),
('m16', 'Nortriptilina', '{"Pamelor"}', 'Tricíclico', '{"Antidepressivo"}', 'Inibição seletiva de NET com efeitos anticolinérgicos menores.', 'Melhor tolerabilidade entre os TCAs para uso na população geriátrica.', '{"Boca seca","Constipação","Tontura"}', '{"Fase aguda após IAM"}', '{"Oral","Cápsula"}', 'Considerados como opção robusta de segunda, terceira ou quarta linha nos fluxogramas de depressões unipolares difíceis de tratar ou TOCs graves. São os representantes mais antigos de agentes monoaminérgicos e ainda carregam uma das eficácias brutas mais consistentes na psiquiatria, mas são tolhidos frequentemente pelo perfil tóxico de efeitos colaterais cardíacos e anticolinérgicos.', '[{"condition":"Profilaxia de Enxaqueca","evidence":"Alto","justification":"A ação crônica multifatorial estabiliza os limiares vasculares neurogênicos da dor cefálica contínua (ex: Amitriptilina)."},{"condition":"Enurese Noturna (Infantil / Adulta)","evidence":"Moderado","justification":"A grande afinidade anticolinérgica (M1) deprime a contração tônica da bexiga noturna."},{"condition":"Neuralgia do Trigêmeo e Herpes","evidence":"Alto","justification":"Modulam efetivamente os impulsos neurais somatossensoriais hiperativos não-responsivos a AINEs."}]'::jsonb, '[{"condition":"Depressão Maior Refratária","line":"3ª Linha","evidence":"Robusto","justification":"A eficácia crua é espetacular, mas seu uso é relegado para linhas tardias devido à alta toxicidade e intolerabilidade dos efeitos colaterais."}]'::jsonb, '{"serotonergic","noradrenergic","anticholinergic","antihistaminic"}'),
('m17', 'Mirtazapina', '{"Remeron"}', 'Tetracíclico', '{"Antidepressivo"}', 'Antagonista alfa-2, H1 potente, 5-HT2A e 5-HT3.', 'Em baixas doses o efeito H1 predomina gerando forte sedação e ganho de peso.', '{"Aumento de apetite drástico","Ganho de peso","Sedação","Boca seca"}', '{"Uso concomitante com IMAO"}', '{"Oral","Comprimido","Comprimido Orodispersível"}', 'Antidepressivo tetracíclico atípico de alta eficácia (bloqueio de receptores Alfa-2 adrenérgicos e receptores de serotonina 5-HT2 e 5-HT3). Carrega excelente efeito ansiolítico e indutor do sono.', '[{"condition":"Insônia Secundária à Depressão","evidence":"Alto","justification":"Bloqueio histamínico H1 superpotente gera forte sonolência à noite (curiosamente, doses menores de 15mg induzem mais sono do que 45mg)."},{"condition":"Estimulação de Apetite em Idosos/Câncer","evidence":"Alto","justification":"Intenso aumento de apetite pelo sinergismo de antagonismo H1 e 5-HT2C, combatendo a caquexia."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Antidepressivo tetracíclico atípico. Fantástica eficácia contra ansiedade, insônia e sintomas somáticos acoplados."}]'::jsonb, '{"serotonergic","noradrenergic","antihistaminic","metabolic_risk","gold_standard"}'),
('m18', 'Maprotilina', '{"Ludiomil"}', 'Tetracíclico', '{"Antidepressivo"}', 'Inibidor de recaptação de noradrenalina potente e antagonista H1.', 'Eileptogênica, contraindicado em transtornos convulsivos.', '{"Convulsões","Sedação","Boca seca típica"}', '{"Transtornos convulsivos prévios","IAM recente"}', '{"Oral","Comprimido"}', 'Considerados como opção robusta de segunda, terceira ou quarta linha nos fluxogramas de depressões unipolares difíceis de tratar ou TOCs graves. São os representantes mais antigos de agentes monoaminérgicos e ainda carregam uma das eficácias brutas mais consistentes na psiquiatria, mas são tolhidos frequentemente pelo perfil tóxico de efeitos colaterais cardíacos e anticolinérgicos.', '[{"condition":"Profilaxia de Enxaqueca","evidence":"Alto","justification":"A ação crônica multifatorial estabiliza os limiares vasculares neurogênicos da dor cefálica contínua (ex: Amitriptilina)."},{"condition":"Enurese Noturna (Infantil / Adulta)","evidence":"Moderado","justification":"A grande afinidade anticolinérgica (M1) deprime a contração tônica da bexiga noturna."},{"condition":"Neuralgia do Trigêmeo e Herpes","evidence":"Alto","justification":"Modulam efetivamente os impulsos neurais somatossensoriais hiperativos não-responsivos a AINEs."}]'::jsonb, '[{"condition":"Depressão Maior Refratária","line":"3ª Linha","evidence":"Robusto","justification":"A eficácia crua é espetacular, mas seu uso é relegado para linhas tardias devido à alta toxicidade e intolerabilidade dos efeitos colaterais."}]'::jsonb, '{"serotonergic","noradrenergic","anticholinergic","antihistaminic"}'),
('m19', 'Fenelzina', '{"Nardil"}', 'iMAO', '{"Antidepressivo"}', 'Inibição irreversível não-seletiva (MAO-A e MAO-B) derivado de hidrazina.', 'Restrição nutricional estrita obrigatória por risco de crise simpática.', '{"Hipotensão ortostática grave","Ganho de peso","Insônia","Disfunção sexual"}', '{"Uso concomitante com ISRS","Alimentos ricos em tiramina sem restrição dietética","Feocromocitoma"}', '{"Oral","Comprimido"}', 'São drogas inestimáveis, e ultimamente pouco utilizadas, com perfis curativos incomparáveis para quem exibe fobias atípicas sociais, ou depressões reativas com ganho de peso, paralisias hiperssoníferas e chumbo emocional (''Leaden Paralysis''). Sua complexa margem de dieta em compostos tiramínicos exige alta competência e monitoria, fazendo dessa uma quarta linha excepcional pra nichos.', '[{"condition":"Anedonia Refratária Absoluta e Retardo Psicomotor Isolado","evidence":"Anedótico","justification":"Promissora elevação brutal da neuro-volição quando a ausência da quebra orgânica da Monoamina Oxidase reverte déficits mesolímbicos inertes de anos a fio."},{"condition":"Doença de Parkinson Adjuvante","evidence":"Moderado","justification":"Ao pararem a degradação da dopamina em níveis profundos por vias B nos ganglios de base, aliviam os sintomas distônicos parkinsonianos atípicos."}]'::jsonb, '[{"condition":"Depressão Refratária / Atípica com Anedonia Grave","line":"Refratária","evidence":"Robusto","justification":"Eficácia biológica incomparável pela inibição profunda e irreversível da quebra de todas as três principais monoaminas."}]'::jsonb, '{"serotonergic","noradrenergic","dopaminergic","cardiac_risk"}'),
('m20', 'Tranilcipromina', '{"Parnate"}', 'iMAO', '{"Antidepressivo"}', 'Inibição irreversível da MAO-A e MAO-B. Semelhante química com anfetaminas.', 'Efeito altamente ativador com riscos noradrenérgicos letais.', '{"Risco de crise hipertensiva aguda","Anorexia","Insônia","Inquietação excessiva"}', '{"Doença cardiovascular preexistente","Uso concomitante com inibidores de recaptação de serotonina","Alimentos contendo tiramina"}', '{"Oral","Comprimido"}', 'São drogas inestimáveis, e ultimamente pouco utilizadas, com perfis curativos incomparáveis para quem exibe fobias atípicas sociais, ou depressões reativas com ganho de peso, paralisias hiperssoníferas e chumbo emocional (''Leaden Paralysis''). Sua complexa margem de dieta em compostos tiramínicos exige alta competência e monitoria, fazendo dessa uma quarta linha excepcional pra nichos.', '[{"condition":"Anedonia Refratária Absoluta e Retardo Psicomotor Isolado","evidence":"Anedótico","justification":"Promissora elevação brutal da neuro-volição quando a ausência da quebra orgânica da Monoamina Oxidase reverte déficits mesolímbicos inertes de anos a fio."},{"condition":"Doença de Parkinson Adjuvante","evidence":"Moderado","justification":"Ao pararem a degradação da dopamina em níveis profundos por vias B nos ganglios de base, aliviam os sintomas distônicos parkinsonianos atípicos."}]'::jsonb, '[{"condition":"Depressão Refratária / Atípica com Anedonia Grave","line":"Refratária","evidence":"Robusto","justification":"Eficácia biológica incomparável pela inibição profunda e irreversível da quebra de todas as três principais monoaminas."}]'::jsonb, '{"serotonergic","noradrenergic","dopaminergic","cardiac_risk"}'),
('m21', 'Moclobemida', '{"Aurorix"}', 'iMAO', '{"Antidepressivo"}', 'Inibidor Reversível da MAO-A (RIMA).', 'Menor risco dietético perante a tiramina em comparação aos IMAOs tradicionais.', '{"Insônia","Tontura","Náusea"}', '{"Uso com Selegilina","Tireotoxicose"}', '{"Oral","Comprimido"}', 'São drogas inestimáveis, e ultimamente pouco utilizadas, com perfis curativos incomparáveis para quem exibe fobias atípicas sociais, ou depressões reativas com ganho de peso, paralisias hiperssoníferas e chumbo emocional (''Leaden Paralysis''). Sua complexa margem de dieta em compostos tiramínicos exige alta competência e monitoria, fazendo dessa uma quarta linha excepcional pra nichos.', '[{"condition":"Anedonia Refratária Absoluta e Retardo Psicomotor Isolado","evidence":"Anedótico","justification":"Promissora elevação brutal da neuro-volição quando a ausência da quebra orgânica da Monoamina Oxidase reverte déficits mesolímbicos inertes de anos a fio."},{"condition":"Doença de Parkinson Adjuvante","evidence":"Moderado","justification":"Ao pararem a degradação da dopamina em níveis profundos por vias B nos ganglios de base, aliviam os sintomas distônicos parkinsonianos atípicos."}]'::jsonb, '[{"condition":"Depressão Refratária / Atípica com Anedonia Grave","line":"Refratária","evidence":"Robusto","justification":"Eficácia biológica incomparável pela inibição profunda e irreversível da quebra de todas as três principais monoaminas."}]'::jsonb, '{"serotonergic","noradrenergic","dopaminergic","cardiac_risk"}'),
('m27', 'Lítio', '{"Carbolitium"}', 'Estabilizador de Humor', '{"Estabilizador"}', 'Substituição iônica alterando via da IMPase e PKC, inibição de GSK-3 beta.', 'Acompanhar litemia, TSH e creatinina. Interações farmacocinéticas predominantemente renais.', '{"Poliúria","Polidipsia","Tremor fino","Hipotireoidismo induzido","Ganho de peso","Náusea"}', '{"Insuficiência renal grave","Doença cardiovascular grave","Desidratação e depleção de sódio"}', '{"Oral","Comprimido","Comprimido de Liberação Modificada"}', 'O Carbonato de Lítio é o estabilizador de humor padrão-ouro absoluto na psiquiatria. Seu mecanismo de ação é multifatorial e altamente especializado no nível intracelular: (1) entra nos neurônios através de canais de sódio rápidos; (2) inibe a enzima Inositol Monofosfatase (IMPase), esgotando os níveis de inositol celular e atenuando a sinalização do fosfatidilinositol hiperativo; (3) inibe diretamente a Glicogênio Sintase Quinase-3 beta (GSK-3β), promovendo fatores de sobrevivência celular, neuroplasticidade e aumento de BDNF; (4) modula a liberação de neurotransmissores, reduzindo o excesso de glutamato e dopamina enquanto facilita a transmissão serotoninérgica (especialmente via receptores pós-sinápticos 5-HT1A) e gabaérgica. Destaca-se também como o único agente farmacológico com eficácia robusta e direta na redução de taxas de suicídio consumado em pacientes bipolares.', '[{"condition":"Potencialização de Antidepressivos na Depressão Maior Refratária","evidence":"Alto","justification":"Estratégia de potencialização clássica de primeira linha com altíssima taxa de eficácia clínica na reversão de apatia."},{"condition":"Transtorno Esquizoafetivo","evidence":"Moderado","justification":"Auxilia no controle dos sintomas cíclicos afetivos de mania/depressão sobrepostos aos sintomas psicóticos."},{"condition":"Agressividade e Impulsividade Grave","evidence":"Moderado","justification":"Modula o comportamento explosivo e explosões de fúria refratárias em pacientes de alta vulnerabilidade neurológica."}]'::jsonb, '[{"condition":"Transtorno Bipolar (Prevenção e Manutenção de Fases)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Demonstra eficácia superior a longo prazo na prevenção de novos episódios de mania e de depressão crônica."},{"condition":"Mania Bipolar Aguda","line":"1ª Linha","evidence":"Robusto","justification":"Desacelera rapidamente o taquipsiquismo, a grandiosidade ideativa e a impulsividade motora em episódios de euforia extrema."},{"condition":"Redução do Risco de Suicídio no Transtorno Bipolar","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Apresenta propriedades antisuicidas exclusivas e diretas comprovadas por amplos estudos epidemiológicos observacionais."}]'::jsonb, '{"gold_standard","cardiac_risk"}'),
('m28', 'Valproato', '{"Depakene","Depakote"}', 'Estabilizador de Humor', '{"Estabilizador"}', 'Múltiplos mecanismos: bloqueio de canais de sódio, potenciação GABAérgica, inibição de histona deacetilase.', 'Extremamente teratogênico (DTNs em recém-nascidos). Forte inibidor UGT/fase II.', '{"Alopecia","Tremor","Hepatotoxicidade","Trombocitopenia","Teratogenicidade (Espinha bífida)"}', '{"Doença hepática aguda","Distúrbios do ciclo da ureia","Gravidez"}', '{"Oral","Comprimido","Xarope","Intravenoso"}', 'Ancoram toda a prática bipolar psiquiátrica clínica, inibindo mecanicamente flutuações e descargas drásticas de polarizações afetivas da mania impulsora fulminante. Funcionam também em depressões não reativas unipolares de traços melancólicos instáveis como tratamento ponte principal a longo prazo por prevenir ciclagens contínuas.', '[{"condition":"Prevenção da Ideação Suicida Crônica","evidence":"Alto","justification":"Estilo e dados em base inquestionável em pacientes responsivos ao lítio (exigido com dosagens de manutenção)."},{"condition":"Transtorno Neurocognitivo Frontotemporal de Impulsividade","evidence":"Baixo","justification":"Valproato tem demonstrado acalmar explosões atreladas à disfunção orbitofrontal por lesão, minimamente."},{"condition":"Dores Crônicas em ''Gatilho''","evidence":"Alto","justification":"Ouvimos relatos (anticonvulsivantes como Pregabalina ou Carbamazepina) desativando fluxos sensoriais na neuropatia de origem diabética."}]'::jsonb, '[{"condition":"Transtorno Bipolar (Manutenção e Prevenção de Fases)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Reduz drasticamente taxas de recaídas em ambas as polaridades (principalmente mania para Lítio/Valproato e depressão para Lamotrigina)."},{"condition":"Mania Bipolar Aguda","line":"1ª Linha","evidence":"Robusto","justification":"Doses otimizadas de Carbonato de Lítio ou Ácido Valproico desaceleram o surto psicomotor maníaco em poucos dias."}]'::jsonb, '{"gabaergic","metabolic_risk"}'),
('m29', 'Lamotrigina', '{"Lamictal"}', 'Estabilizador de Humor', '{"Estabilizador"}', 'Bloqueio seletivo de VSSCs. Retarda ativação do glutamato central.', 'Risco da Síndrome de Stevens-Johnson requer escalonamento milimétrico em 4 a 6 semanas.', '{"Rash cutâneo (benigno ou maligno SJS/TEN)","Cefaleia","Diplopia","Tontura"}', '{}', '{"Oral","Comprimido","Comprimido Mastigável"}', 'Ancoram toda a prática bipolar psiquiátrica clínica, inibindo mecanicamente flutuações e descargas drásticas de polarizações afetivas da mania impulsora fulminante. Funcionam também em depressões não reativas unipolares de traços melancólicos instáveis como tratamento ponte principal a longo prazo por prevenir ciclagens contínuas.', '[{"condition":"Prevenção da Ideação Suicida Crônica","evidence":"Alto","justification":"Estilo e dados em base inquestionável em pacientes responsivos ao lítio (exigido com dosagens de manutenção)."},{"condition":"Transtorno Neurocognitivo Frontotemporal de Impulsividade","evidence":"Baixo","justification":"Valproato tem demonstrado acalmar explosões atreladas à disfunção orbitofrontal por lesão, minimamente."},{"condition":"Dores Crônicas em ''Gatilho''","evidence":"Alto","justification":"Ouvimos relatos (anticonvulsivantes como Pregabalina ou Carbamazepina) desativando fluxos sensoriais na neuropatia de origem diabética."}]'::jsonb, '[{"condition":"Transtorno Bipolar (Manutenção e Prevenção de Fases)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Reduz drasticamente taxas de recaídas em ambas as polaridades (principalmente mania para Lítio/Valproato e depressão para Lamotrigina)."},{"condition":"Mania Bipolar Aguda","line":"1ª Linha","evidence":"Robusto","justification":"Doses otimizadas de Carbonato de Lítio ou Ácido Valproico desaceleram o surto psicomotor maníaco em poucos dias."}]'::jsonb, '{"glutamatergic"}'),
('m30', 'Carbamazepina', '{"Tegretol"}', 'Estabilizador de Humor', '{"Estabilizador"}', 'Bloqueio de canais de sódio voltagem-dependentes. Autoindutora do metabolismo.', 'Um dos mais potentes atuadores nas enzimas do fígado (CYP3A4, 1A2, 2C9).', '{"Diplopia","Ataxia","Hiponatremia","Leucopenia","Exantema (HLA-B*1502 em asiáticos)"}', '{"Depressão da medula óssea","Esmagar comprimido de liberação prolongada"}', '{"Oral","Comprimido","Suspensão","Solução Injetável"}', 'Ancoram toda a prática bipolar psiquiátrica clínica, inibindo mecanicamente flutuações e descargas drásticas de polarizações afetivas da mania impulsora fulminante. Funcionam também em depressões não reativas unipolares de traços melancólicos instáveis como tratamento ponte principal a longo prazo por prevenir ciclagens contínuas.', '[{"condition":"Prevenção da Ideação Suicida Crônica","evidence":"Alto","justification":"Estilo e dados em base inquestionável em pacientes responsivos ao lítio (exigido com dosagens de manutenção)."},{"condition":"Transtorno Neurocognitivo Frontotemporal de Impulsividade","evidence":"Baixo","justification":"Valproato tem demonstrado acalmar explosões atreladas à disfunção orbitofrontal por lesão, minimamente."},{"condition":"Dores Crônicas em ''Gatilho''","evidence":"Alto","justification":"Ouvimos relatos (anticonvulsivantes como Pregabalina ou Carbamazepina) desativando fluxos sensoriais na neuropatia de origem diabética."}]'::jsonb, '[{"condition":"Transtorno Bipolar (Manutenção e Prevenção de Fases)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Reduz drasticamente taxas de recaídas em ambas as polaridades (principalmente mania para Lítio/Valproato e depressão para Lamotrigina)."},{"condition":"Mania Bipolar Aguda","line":"1ª Linha","evidence":"Robusto","justification":"Doses otimizadas de Carbonato de Lítio ou Ácido Valproico desaceleram o surto psicomotor maníaco em poucos dias."}]'::jsonb, '{"cardiac_risk"}'),
('m31', 'Bupropiona', '{"Wellbutrin","Bup"}', 'Antidepressivo Atípico', '{"Antidepressivo","Estimulante"}', 'Inibidor da recaptação de noradrenalina e dopamina (IRND).', 'Não prejudica a função sexual masculina e ajuda na cessação tabágica.', '{"Agitação","Insônia","Ansiedade","Redução de limiar convulsivo","Perda de peso"}', '{"Transtorno convulsivo atual ou pregresso","Anorexia ou bulimia nervosa","Uso abrupto de descontinuação de álcool"}', '{"Oral","Comprimido de Liberação Prologada (XL/SR)"}', 'Antidepressivo atípico que atua como Inibidor de Recaptação de Dopamina e Noradrenalina (IRND). Destaca-se na prática clínica por sua ausência de efeitos colaterais sexuais significativos e por não promover o ganho de peso, sendo frequentemente utilizado para combater sintomas de apatia, fadiga e anedonia.', '[{"condition":"TDAH (Intolerância ou Refratariedade a Estimulantes)","evidence":"Alto","justification":"Aumenta o tônus adrenérgico/dopaminérgico pré-frontal, melhorando foco e organização de forma suave."},{"condition":"Disfunção Sexual Induzida por ISRS/ISRSN","evidence":"Alto","justification":"Potencializa a atividade dopaminérgica mesolímbica, revertendo a anedonia sexual e o atraso ejaculatório."},{"condition":"Transtorno Compulsivo Alimentar / Obesidade","evidence":"Moderado","justification":"Reduz apetite e impulsos por doces; potencializado quando combinado com naltrexona."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente alternativa ou adjuvante para quadros com marcante lentificação psicomotora, fadiga física ou ganho de peso sob outros antidepressivos."},{"condition":"Cessação do Tabagismo","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Antagonismo de receptores nicotínicos e modulação dopaminérgica reduzem substancialmente a fissura (craving) e sintomas de abstinência de nicotina."}]'::jsonb, '{"dopaminergic","noradrenergic"}'),
('m32', 'Trazodona', '{"Donaren"}', 'SARI', '{"Antidepressivo","Ansiolitico"}', 'Antagonista 5-HT2A potente e inibidor SERT mais fraco. Bloqueador H1.', 'Amplamente utilizada de forma off-label para insônia por ansiedade. Risco de priapismo.', '{"Sedação acentuada","Hipotensão ortostática","Boca seca","Priapismo (raro mas grave)"}', '{"Uso concomitante com saquinavir/ritonavir (em teoria)"}', '{"Oral","Comprimido"}', 'Antidepressivo pertencente à classe dos Inibidores de Recaptação e Antagonistas de Serotonina (SARI). Possui uma farmacologia dependente da dose: em baixas dosagens (25-100mg) atua como um potente hipnótico devido ao seu forte bloqueio de receptores 5-HT2A, H1 e alfa-1 adrenérgicos; em dosagens elevadas (150-300mg) exibe efeitos antidepressivos consistentes pela inibição do SERT.', '[{"condition":"Insônia Secundária a Antidepressivos / Ansiedade","evidence":"Alto","justification":"Considerado um padrão clínico prático excelente para indução e consolidação do sono profundo de ondas lentas sem causar dependência ou tolerância."},{"condition":"Disfunção Cognitiva e Agitação em Demências","evidence":"Moderado","justification":"Auxilia a atenuar quadros de agitação psicomotora noturna (síndrome do pôr do sol) e descontrole em idosos com demência."}]'::jsonb, '[{"condition":"Depressão Maior (TDM)","line":"2ª Linha","evidence":"Moderado","justification":"Eficaz em monoterapia em doses elevadas, mas comumente associada como adjuvante em depressões acompanhadas de forte insônia."}]'::jsonb, '{"serotonergic","antihistaminic"}'),
('m33', 'Vortioxetina', '{"Brintellix","Trintellix"}', 'Multimodal', '{"Antidepressivo"}', 'Inibe SERT (primário). Modula 5-HT1A, 5-HT3 e 5-HT7.', 'Vem demonstrando superioridade restaurando disfunções cognitivas na DM.', '{"Náusea muito forte","Prurido","Sonolência"}', '{"Uso concomitante com IMAO"}', '{"Oral","Comprimido"}', 'Antidepressivo de mecanismo de ação multimodal único. Além de inibir o SERT, atua como agonista 5-HT1A, agonista parcial 5-HT1B e antagonista dos receptores 5-HT3, 5-HT1D e 5-HT7. Essa modulação sináptica complexa promove a elevação sustentada de serotonina, noradrenalina, dopamina, acetilcolina e histamina no córtex pré-frontal, resultando em uma potente ação pró-cognitiva e antidepressiva.', '[{"condition":"Transtorno de Ansiedade Generalizada (TAG)","evidence":"Alto","justification":"Regula com excelência o humor e diminui a preocupação patológica por meio da modulação sináptica do sistema serotoninérgico."},{"condition":"Disfunção Sexual induzida por ISRSs","evidence":"Moderado","justification":"Apresenta excelente taxa de tolerabilidade sexual devido ao seu antagonismo específico 5-HT3."}]'::jsonb, '[{"condition":"Depressão Maior (TDM) com Disfunção Cognitiva","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Único antidepressivo aprovado com forte evidência científica direta na melhora de sintomas cognitivos (concentração, foco e memória de trabalho) associados à depressão."}]'::jsonb, '{"serotonergic","gold_standard"}'),
('m34', 'Agomelatina', '{"Valdoxan"}', 'Melatoninérgico', '{"Antidepressivo"}', 'Agonista potentes MT1/MT2 e um antagonista 5-HT2C pre-sináptico.', 'Restritivo a função hepática prévia, não usar em hepatopatas.', '{"Elevação sérica de transaminases hepáticas","Cefaleia","Hiperidrose"}', '{"Insuficiência hepática prévia","Uso com fluvoxamina (inibidores potentes de CYP1A2)"}', '{"Oral","Comprimido"}', 'Antidepressivo melatoninérgico atípico de ação inovadora. Atua como agonista seletivo e potente dos receptores MT1 e MT2 de melatonina, associado a um antagonismo dos receptores serotoninérgicos 5-HT2C. Esse sinergismo resincroniza os ritmos circadianos desregulados na depressão, restaurando a arquitetura do sono e aliviando a anedonia e prostração diurna, livre de efeitos colaterais sexuais ou metabólicos. Requer controle periódico de enzimas hepáticas.', '[{"condition":"Ansiedade Generalizada (TAG)","evidence":"Moderado","justification":"O bloqueio de receptores 5-HT2C promove uma regulação ansiolítica suave e aumento secundário de DA/NE pré-frontal."},{"condition":"Distúrbio do Ritmo Sono-Vigília","evidence":"Alto","justification":"Rápida resincronização do relógio biológico central no núcleo supraquiasmático."}]'::jsonb, '[{"condition":"Depressão Maior (TDM) com Sintomas Ansiosos ou de Sono","line":"1ª Linha","evidence":"Robusto","justification":"Promove melhora rápida da qualidade do sono e anedonia, sendo muito bem tolerado quanto à libido e peso corporal."}]'::jsonb, '{"serotonergic"}'),
('m35', 'Buspirona', '{"Ansitec","Buspar"}', 'Ansiolítico', '{"Ansiolitico"}', 'Agonista parcial 5-HT1A, inibição da regulação down dos receptores.', 'Não oferece potencial de abuso, requerendo de 2 a 4 semanas para pleno efeito.', '{"Vertigem","Cefaleia","Nervosismo paradoxal","Tontura leve"}', '{"Uso concomitante com IMAO (teórico)"}', '{"Oral","Comprimido"}', 'Ansiolítico puro não-benzodiazepínico. Atua especificamente como agonista parcial de alta afinidade dos receptores serotoninérgicos 5-HT1A, promovendo a regulação adaptativa pré-sináptica (down-regulation de autorreceptores) e regulação pós-sináptica límbica. Alivia a ansiedade crônica de forma gradual, sem causar sedação, relaxamento muscular, dependência física, tolerância ou síndromes de abstinência.', '[{"condition":"Potencialização de Antidepressivos na Depressão ou TOC","evidence":"Alto","justification":"Adicionada a ISRS para amplificar a resposta terapêutica global e mitigar a disfunção sexual induzida pelos mesmos."}]'::jsonb, '[{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Excelente opção para tratamento crônico e de longo prazo de sintomas ansiosos leves a moderados, especialmente em pacientes intolerantes a BZDs ou com histórico de adição."}]'::jsonb, '{"serotonergic"}'),
('m36', 'Clonazepam', '{"Rivotril"}', 'Benzodiazepínico', '{"Ansiolitico","Anticonvulsivante"}', 'Modulador alostérico positivo (MAP) do receptor GABA-A.', 'Longa duração.', '{"Sonolência","Fadiga","Comprometimento cognitivo leve","Dependência"}', '{"Miastenia gravis","Glaucoma de ângulo fechado","Insuficiência respiratória grave"}', '{"Oral","Comprimido","Comprimido Sublingual","Gotas"}', 'Fármacos sintomáticos essenciais para alívio imediatista, rápido e ponte provisória para quadros de agitação em internamentos e neutralização instantânea de ataques de pânico avassaladores. Sua inclusão deve prever sempre a retirada a curto prazo (2-6 semanas) pela escalada de neuro-tolerância anatômica subjacente que cronicamente prejudica o prognóstico cognitivo e aditivo do paciente.', '[{"condition":"Espasmos Musculares Complexos / Cãibras Rígidas","evidence":"Moderado","justification":"Propriedade original robusta miorrelaxante, deprimindo a espasticidade motora voluntária."},{"condition":"Status Epilepticus / Epilepsia Aguda","evidence":"Alto","justification":"Redução maciça do limiar convulsivo ao deflagrar GABA, hiperpolarizando os feixes elétricos excessivos temporariamente."},{"condition":"Síndrome de Abstinência Alcoólica Grave","evidence":"Alto","justification":"Uso mandatório cruzado para evitar morte induzida e delerium tremens quando da retirada crônica exógena do álcool cerebral."}]'::jsonb, '[{"condition":"Crise de Ansiedade / Ataque de Pânico Agudo","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de socorro para alívio imediato (minutos) de crises de pânico descontroladas."},{"condition":"Estado de Mal Epiléptico e Crises Convulsivas","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"O aumento na condutância de cloreto induz hiperpolarização central imediata, cessando disparos elétricos generalizados."},{"condition":"Prevenção de Abstinência Alcoólica Grave","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Substituição cruzada crucial de receptores de GABA para evitar delirium tremens, alucinações e convulsões por retirada súbita de álcool."}]'::jsonb, '{"gabaergic","gold_standard"}'),
('m37', 'Diazepam', '{"Valium"}', 'Benzodiazepínico', '{"Ansiolitico","Anticonvulsivante"}', 'Modulador alostérico positivo do receptor GABA-A. Ação prolongada por metabólitos ativos.', 'Metabólito ativo (desmetildiazepam) estende a meia-vida.', '{"Sedação profunda","Ataxia","Fadiga","Dependência"}', '{"Miastenia gravis","Apneia do sono","Glaucoma de ângulo fechado"}', '{"Oral","Comprimido","Intramuscular","Intravenoso"}', 'Fármacos sintomáticos essenciais para alívio imediatista, rápido e ponte provisória para quadros de agitação em internamentos e neutralização instantânea de ataques de pânico avassaladores. Sua inclusão deve prever sempre a retirada a curto prazo (2-6 semanas) pela escalada de neuro-tolerância anatômica subjacente que cronicamente prejudica o prognóstico cognitivo e aditivo do paciente.', '[{"condition":"Espasmos Musculares Complexos / Cãibras Rígidas","evidence":"Moderado","justification":"Propriedade original robusta miorrelaxante, deprimindo a espasticidade motora voluntária."},{"condition":"Status Epilepticus / Epilepsia Aguda","evidence":"Alto","justification":"Redução maciça do limiar convulsivo ao deflagrar GABA, hiperpolarizando os feixes elétricos excessivos temporariamente."},{"condition":"Síndrome de Abstinência Alcoólica Grave","evidence":"Alto","justification":"Uso mandatório cruzado para evitar morte induzida e delerium tremens quando da retirada crônica exógena do álcool cerebral."}]'::jsonb, '[{"condition":"Crise de Ansiedade / Ataque de Pânico Agudo","line":"1ª Linha","evidence":"Robusto","justification":"Tratamento de socorro para alívio imediato (minutos) de crises de pânico descontroladas."},{"condition":"Estado de Mal Epiléptico e Crises Convulsivas","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"O aumento na condutância de cloreto induz hiperpolarização central imediata, cessando disparos elétricos generalizados."},{"condition":"Prevenção de Abstinência Alcoólica Grave","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Substituição cruzada crucial de receptores de GABA para evitar delirium tremens, alucinações e convulsões por retirada súbita de álcool."}]'::jsonb, '{"gabaergic"}'),
