('m42', 'Zolpidem', '{"Stilnox"}', 'Hipnótico-Z', '{"Hipnotico"}', 'Agonista seletivo do receptor GABA-A com preferência pela subunidade α1.', 'Uso off-label frequente no Brasil para insônia.', '{"Sonambulismo","Amnésia anterógrada","Alucinações","Tontura"}', '{"Histórico de parassonia complexa induzida por zolpidem"}', '{"Oral","Comprimido","Comprimido Sublingual"}', 'Os indutores de ação preferencial do receptor GABA em subunidade sedativa. Altamente seletivo pra iniciação e manutenção (com liberação prolongada) para pânico de arquitetura noturna, o tempo percorrido total deve ser acompanhado não excedendo prazos breves (dias a raramente poucas semanas) face que comportamentos automáticos amnésicos (parassonias complexas) são perigos comuns em excessos.', '[{"condition":"Cura Temporária Paradoxal na Catatonia","evidence":"Baixo","justification":"''Despertar de Lázaro'': o reestabelecimento surpreendente por instantes (horas) da fala e coordenação da fase dura catatônica sem causa metabólica direta subjacente."}]'::jsonb, '[{"condition":"Insônia de Curta Duração (Dificuldade de Indução)","line":"1ª Linha","evidence":"Robusto","justification":"Agonistas seletivos da subunidade alfa-1 do receptor GABA-A. Indução extremamente rápida e preservação de arquitetura do sono."}]'::jsonb, '{"gabaergic"}'),
('m43', 'Zopiclona', '{"Imovane"}', 'Hipnótico-Z', '{"Hipnotico"}', 'Agonista não seletivo do sítio benzodiazepínico no receptor GABA-A.', 'Disponível no Brasil. Queixas frequentes de gosto metálico.', '{"Gosto amargo/metálico","Sonolência residual","Boca seca","Descoordenação"}', '{"Insuficiência respiratória grave","Miastenia gravis"}', '{"Oral","Comprimido"}', 'Os indutores de ação preferencial do receptor GABA em subunidade sedativa. Altamente seletivo pra iniciação e manutenção (com liberação prolongada) para pânico de arquitetura noturna, o tempo percorrido total deve ser acompanhado não excedendo prazos breves (dias a raramente poucas semanas) face que comportamentos automáticos amnésicos (parassonias complexas) são perigos comuns em excessos.', '[{"condition":"Cura Temporária Paradoxal na Catatonia","evidence":"Baixo","justification":"''Despertar de Lázaro'': o reestabelecimento surpreendente por instantes (horas) da fala e coordenação da fase dura catatônica sem causa metabólica direta subjacente."}]'::jsonb, '[{"condition":"Insônia de Curta Duração (Dificuldade de Indução)","line":"1ª Linha","evidence":"Robusto","justification":"Agonistas seletivos da subunidade alfa-1 do receptor GABA-A. Indução extremamente rápida e preservação de arquitetura do sono."}]'::jsonb, '{"gabaergic"}'),
('m44', 'Eszopiclona', '{"Prysma"}', 'Hipnótico-Z', '{"Hipnotico"}', 'Enantiômero S ativo da zopiclona com afinidade extrínseca no GABA-A.', 'Menor tolerância a longo prazo, mas com gosto desagradável associado.', '{"Disgeusia (gosto ruim)","Cefaleia","Sonolência diurna","Tontura"}', '{"Depressão respiratória grave"}', '{"Oral","Comprimido"}', 'Os indutores de ação preferencial do receptor GABA em subunidade sedativa. Altamente seletivo pra iniciação e manutenção (com liberação prolongada) para pânico de arquitetura noturna, o tempo percorrido total deve ser acompanhado não excedendo prazos breves (dias a raramente poucas semanas) face que comportamentos automáticos amnésicos (parassonias complexas) são perigos comuns em excessos.', '[{"condition":"Cura Temporária Paradoxal na Catatonia","evidence":"Baixo","justification":"''Despertar de Lázaro'': o reestabelecimento surpreendente por instantes (horas) da fala e coordenação da fase dura catatônica sem causa metabólica direta subjacente."}]'::jsonb, '[{"condition":"Insônia de Curta Duração (Dificuldade de Indução)","line":"1ª Linha","evidence":"Robusto","justification":"Agonistas seletivos da subunidade alfa-1 do receptor GABA-A. Indução extremamente rápida e preservação de arquitetura do sono."}]'::jsonb, '{"gabaergic"}'),
('m45', 'Gabapentina', '{"Neurontin"}', 'Anticonvulsivante', '{"Anticonvulsivante","Gabapentinoide","Ansiolitico"}', 'Inibidor de canais de cálcio dependentes de voltagem (subunidade α2δ).', 'Uso off-label para dor neuropática, ansiedade, abstinência. Sem interação CYP significativa.', '{"Sedação","Tontura","Ganho de peso","Edema periférico"}', '{}', '{"Oral","Cápsula","Comprimido"}', 'Moduladores dos canais de cálcio voltagem-dependentes que acalmam a excitabilidade neuronal excessiva. Excelente atuação em ansiedade somática grave e quadros dolorosos associados.', '[{"condition":"Insônia Secundária à Dor/Ansiedade","evidence":"Alto","justification":"Arquitetura do sono mantida, prolongando as fases de sono profundo (ondas lentas) reparador."}]'::jsonb, '[{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Ligação na subunidade alfa-2-delta de canais de cálcio voltagem-dependentes, deprimindo a liberação excessiva de neurotransmissores excitatórios."},{"condition":"Dor Neuropática / Dor Crônica","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Estabilização das vias hiperativas de dor central na medula e cérebro."}]'::jsonb, '{"gabaergic"}'),
('m46', 'Pregabalina', '{"Lyrica"}', 'Anticonvulsivante', '{"Anticonvulsivante","Gabapentinoide","Ansiolitico"}', 'Inibidor de canais de cálcio dependentes de voltagem (subunidade α2δ).', 'Farmacocinética linear previsível, sem CYP. Uso off-label para TAG e fibromialgia.', '{"Tontura","Sonolência","Ganho de peso","Edema periférico"}', '{}', '{"Oral","Cápsula"}', 'Moduladores dos canais de cálcio voltagem-dependentes que acalmam a excitabilidade neuronal excessiva. Excelente atuação em ansiedade somática grave e quadros dolorosos associados.', '[{"condition":"Insônia Secundária à Dor/Ansiedade","evidence":"Alto","justification":"Arquitetura do sono mantida, prolongando as fases de sono profundo (ondas lentas) reparador."}]'::jsonb, '[{"condition":"Transtorno de Ansiedade Generalizada (TAG)","line":"1ª Linha","evidence":"Robusto","justification":"Ligação na subunidade alfa-2-delta de canais de cálcio voltagem-dependentes, deprimindo a liberação excessiva de neurotransmissores excitatórios."},{"condition":"Dor Neuropática / Dor Crônica","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Estabilização das vias hiperativas de dor central na medula e cérebro."}]'::jsonb, '{"gabaergic"}'),
('m47', 'Naltrexona', '{"Revia","Univit"}', 'Antagonista Opioide', '{"Opioide"}', 'Antagonista competitivo em receptores opioides µ, κ, e δ.', 'Usada tipicamente off-label em baixa dose (LDN: 1,5-4,5mg) para dor crônica, fibromialgia, doenças autoimunes.', '{"Náusea leve","Insônia inicial","Cefaleia","Pesadelos vívidos (apenas início)"}', '{"Hepatite aguda ou falência hepática","Uso atual de analgésicos opioides"}', '{"Oral","Comprimido","Cápsula manipulada (LDN)"}', 'Usada na psiquiatria prioritariamente para tratar dependência química (álcool e opioides) inibindo a via de recompensa por vias endorfinérgicas quando consumindo. Diminui os episódios compulsivos (cravings) sem criar dependência.', '[{"condition":"Fibromialgia / Doenças Autoimunes Inflamatórias","evidence":"Moderado","justification":"O formato ''LDN'' (Low Dose Naltrexone ~3mg) modula as células microgliais (anti-inflamatório cerebral), aplacando manifestações nervosas sistêmicas dolorosas excruciantes sem uso imunosupressor."}]'::jsonb, '[{"condition":"Dependência de Álcool e Prevenção de Recaídas","line":"1ª Linha","evidence":"Robusto","justification":"Bloqueia receptores mu-opioides centrais, interrompendo a ativação da via de recompensa dopaminérgica desencadeada pelo etanol."},{"condition":"Dependência de Opioides (Pós-Desintoxicação)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Antagonismo competitivo completo contra opioides exógenos, impedindo qualquer efeito euforizante de recaídas."}]'::jsonb, '{}'),
('m48', 'Memantina', '{"Ebix","Namenda"}', 'Antagonista NMDA', '{"Neuroprotetor","Estabilizador"}', 'Antagonista NMDA (canal iônico de glutamato dependente de voltagem).', 'Uso off-label para TOC resistente, autismo, TDAH. Sem CYP significativo.', '{"Tontura","Cefaleia","Constipação","Confusão episódica"}', '{"Hipersensibilidade conhecida"}', '{"Oral","Comprimido","Solução Oral"}', 'Antagonista NMDA de afinidade moderada que atua protegendo neurônios contra a excitotoxicidade do glutamato crônico, preservando canais normais para aprendizado.', '[{"condition":"Transtorno Obsessivo-Compulsivo Refratário (Adjuvante)","evidence":"Moderado","justification":"Útil em casos severos para frear a hiperatividade glutamatérgica no circuito córtico-estriatal."}]'::jsonb, '[{"condition":"Demência de Alzheimer (Moderada a Grave)","line":"1ª Linha","evidence":"Robusto","justification":"Antagonismo não competitivo do receptor NMDA, bloqueando ruídos patológicos de glutamato de forma voltagem-dependente."}]'::jsonb, '{"glutamatergic"}'),
('m49', 'N-Acetilcisteína (NAC)', '{"Fluimucil","NAC"}', 'Modulador Glutamatérgico', '{"Neuroprotetor","Suplemento"}', 'Modulador glutamatérgico (antiporter xCT, precursor de glutationa).', 'Off-label em TOC, tricotilomania, dependência.', '{"Desconforto gastrointestinal","Náusea","Exantema leve"}', '{"Úlcera péptica ativa severa (precaução)"}', '{"Oral","Comprimido efervescente","Cápsula","Pó","Granulado"}', 'Modulador glutamatérgico indireto (via transportador cistina-glutamato xCT) com potentes efeitos antioxidantes sistêmicos e no SNC.', '[{"condition":"Tricotilomania e Dermatotilomania (Escoriação)","evidence":"Moderado","justification":"A atenuação do glutamato na fenda atenua comportamentos repetitivos de ''grooming'' focados no corpo."},{"condition":"Potencialização em TOC e Adições","evidence":"Moderado","justification":"Ajuda a regular disparos compulsivos e fissura (craving) no abuso de substâncias químicas."}]'::jsonb, '[{"condition":"Intoxicação por Paracetamol (Antídoto)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Precursor direto da glutationa, restabelecendo as reservas de antioxidante hepático contra metabólitos tóxicos."}]'::jsonb, '{"glutamatergic"}'),
('m50', 'Cetamina (Esketamina)', '{"Spravato","Ketamin"}', 'Antagonista NMDA', '{"Anestesico","Antidepressivo"}', 'Antagonista NMDA.', 'Efeito rápido antidepressivo. Crescente uso off-label no Brasil em clínicas especializadas para depressão refratária.', '{"Dissociação","Aumento da pressão arterial","Vertigem","Náusea","Sedação transitória"}', '{"Histórico de aneurisma","Hipertensão grave não controlada","Hipersensibilidade"}', '{"Intranasal","Intravenoso","Comprimido Sublingual (Magistral)"}', 'Modulador glutamatérgico ultrarrápido. O uso de Esketamina intranasal ou Cetamina intravenosa revolucionou o tratamento de crises suicidas agudas e depressões refratárias a múltiplos antidepressivos orais.', '[{"condition":"Dor Crônica Neuropática Refratária","evidence":"Alto","justification":"Infusões seriadas resetam a sensibilização central de receptores de dor crônica."}]'::jsonb, '[{"condition":"Depressão Resistente ao Tratamento (DRT)","line":"Refratária","evidence":"Padrão-Ouro","justification":"Antagonismo NMDA robusto que desencadeia surtos rápidos de liberação de BDNF e restabelece conexões sinápticas em poucas horas."},{"condition":"Comportamento e Ideação Suicida Aguda de Emergência","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Efeito antisuicida ultrarrápido comprovado clinicamente, permitindo ponte de internação segura para ajuste de outros psicotrópicos."}]'::jsonb, '{"glutamatergic","gold_standard"}'),
('m51', 'Metilfenidato', '{"Ritalina","Ritalina LA","Concerta"}', 'Estimulante do SNC (Derivado Piperidínico)', '{"Estimulante"}', 'Inibidor da recaptação de dopamina e noradrenalina (bloqueio DAT e NET).', 'Primeira linha para TDAH. Pode exacerbar ansiedade, tics e psicose.', '{"Insônia","Redução de apetite","Ansiedade","Taquicardia","Cefaleia","Irritabilidade"}', '{"Glaucoma","Hipertireoidismo","Uso concomitante com IMAO"}', '{"Oral","Comprimido","Cápsula de Liberação Modificada"}', 'O alvo matriz central no cerco e manejo do TDAH ou nos extremos narcolépticos/eugeroicos, resultando numa ampliação frontal direta do controle volitivo sobre distrações e limiares letárgicos basais de cansaço extremo. Usualmente associado em baixas dosagens à prática off-label astenica geriátrica se cardiopatias forem extintas.', '[{"condition":"Depressão Resistente / Apática / Geriátrica","evidence":"Moderado","justification":"Promete contornar refratariedades pela melindrosa ação combinada ativando vias mesolímbicas a exaustão."},{"condition":"Fadiga Extrema na Esclerose Múltipla ou Quimioterapia Tumoral","evidence":"Moderado","justification":"Restaura pontualmente qualidade operante mínima frente à anergia central das desmielinizações imunes e destruições quimioterápicas base de letargia aguda."},{"condition":"Transtorno de Compulsão Alimentar","evidence":"Alto","justification":"Lisdexanfetamina é estritamente aprovada nos EUA (bula) na modelagem dopaminérgica saciando refratariedades crônicas obesogênicas graves, minimizando binges mastigatórios automáticos."}]'::jsonb, '[{"condition":"TDAH (Transtorno de Déficit de Atenção e Hiperatividade)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Aumento robusto na disponibilidade cortical de dopamina e noradrenalina, otimizando o controle inibitório e foco."}]'::jsonb, '{"dopaminergic","noradrenergic","gold_standard"}'),
('m52', 'Lisdexanfetamina', '{"Venvanse","Vyvanse","Juneve"}', 'Estimulante do SNC (Anfetamina Pró-droga)', '{"Estimulante"}', 'Pró-droga que sofre hidrólise nas hemácias liberando dextroanfetamina. Inibe a recaptação de DA e NE e promove liberação ativa via VMAT2/reversão de transportadores.', 'Eficácia duradoura e menor potencial de abuso recreativo devido à conversão enzimática lenta. Aprovado para TDAH e Transtorno da Compulsão Alimentar Periódica.', '{"Anorexia","Insônia","Boca seca","Taquicardia","Disforia fim de dose"}', '{"Agitação severa","Glaucoma","Cardiopatia sintomática avançada","Uso concomitante com IMAO"}', '{"Oral","Cápsula"}', 'O alvo matriz central no cerco e manejo do TDAH ou nos extremos narcolépticos/eugeroicos, resultando numa ampliação frontal direta do controle volitivo sobre distrações e limiares letárgicos basais de cansaço extremo. Usualmente associado em baixas dosagens à prática off-label astenica geriátrica se cardiopatias forem extintas.', '[{"condition":"Depressão Resistente / Apática / Geriátrica","evidence":"Moderado","justification":"Promete contornar refratariedades pela melindrosa ação combinada ativando vias mesolímbicas a exaustão."},{"condition":"Fadiga Extrema na Esclerose Múltipla ou Quimioterapia Tumoral","evidence":"Moderado","justification":"Restaura pontualmente qualidade operante mínima frente à anergia central das desmielinizações imunes e destruições quimioterápicas base de letargia aguda."},{"condition":"Transtorno de Compulsão Alimentar","evidence":"Alto","justification":"Lisdexanfetamina é estritamente aprovada nos EUA (bula) na modelagem dopaminérgica saciando refratariedades crônicas obesogênicas graves, minimizando binges mastigatórios automáticos."}]'::jsonb, '[{"condition":"TDAH (Transtorno de Déficit de Atenção e Hiperatividade)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Aumento robusto na disponibilidade cortical de dopamina e noradrenalina, otimizando o controle inibitório e foco."},{"condition":"Transtorno de Compulsão Alimentar Periódica (TCAP)","line":"1ª Linha","evidence":"Robusto","justification":"Modulação estriatal de recompensa e controle de impulsos reduz substancialmente episódios de compulsão alimentar."}]'::jsonb, '{"dopaminergic","noradrenergic","gold_standard"}'),
('m53', 'Dextroanfetamina', '{"Dexedrine"}', 'Estimulante do SNC (Anfetamina)', '{"Estimulante"}', 'Amina simpatomimética de ação indireta. Inibe a recaptação de DA e NE e induz sua liberação massiva dos terminais nervosos e vesículas.', 'Potencial de abuso substancial. Restrita/importada no Brasil na forma isolada.', '{"Taquicardia","Estimulação excessiva","Hipertensão","Agitação","Perda de peso"}', '{"Histórico de dependência","Cardiopatias","Uso concomitante com IMAO"}', '{"Oral","Comprimido","Cápsula"}', 'O alvo matriz central no cerco e manejo do TDAH ou nos extremos narcolépticos/eugeroicos, resultando numa ampliação frontal direta do controle volitivo sobre distrações e limiares letárgicos basais de cansaço extremo. Usualmente associado em baixas dosagens à prática off-label astenica geriátrica se cardiopatias forem extintas.', '[{"condition":"Depressão Resistente / Apática / Geriátrica","evidence":"Moderado","justification":"Promete contornar refratariedades pela melindrosa ação combinada ativando vias mesolímbicas a exaustão."},{"condition":"Fadiga Extrema na Esclerose Múltipla ou Quimioterapia Tumoral","evidence":"Moderado","justification":"Restaura pontualmente qualidade operante mínima frente à anergia central das desmielinizações imunes e destruições quimioterápicas base de letargia aguda."},{"condition":"Transtorno de Compulsão Alimentar","evidence":"Alto","justification":"Lisdexanfetamina é estritamente aprovada nos EUA (bula) na modelagem dopaminérgica saciando refratariedades crônicas obesogênicas graves, minimizando binges mastigatórios automáticos."}]'::jsonb, '[{"condition":"TDAH (Transtorno de Déficit de Atenção e Hiperatividade)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Aumento robusto na disponibilidade cortical de dopamina e noradrenalina, otimizando o controle inibitório e foco."}]'::jsonb, '{"dopaminergic","noradrenergic"}'),
('m54', 'Modafinil', '{"Stavigile","Modiodal"}', 'Estimulante do SNC (Eugeroico)', '{"Estimulante"}', 'Fraca inibição do transportador de dopamina (DAT). Também modula vias de histamina, orexina e glutamato focando promotores de vigília.', 'Ouro em narcolepsia/hipersonia. Off-label pra sonolência/anergia psiquiátrica grave. Baixo perfil de dependência reportado.', '{"Cefaleia","Náusea","Nervosismo","Insônia","Rash cutâneo (SJS raro mas grave)"}', '{"Hipersensibilidade conhecida"}', '{"Oral","Comprimido"}', 'Indutor de vigília (eugeroico) que estimula o alerta cerebral central, sendo o padrão de ouro para narcolepsia e distúrbios do sono do trabalhador de turno alternado.', '[{"condition":"Sonolência Residual Associada à Depressão","evidence":"Moderado","justification":"Auxilia a debelar a anergia e o cansaço mental matinal crônico em pacientes deprimidos estabilizados."},{"condition":"Fadiga na Esclerose Múltipla","evidence":"Moderado","justification":"Melhora o rendimento motor diário e a exaustão neurológica nesses pacientes."}]'::jsonb, '[{"condition":"Narcolepsia e Hipersonia Idiopática","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Excelente indutor de vigília focada no aumento de histamina/orexina por inibição leve do DAT, sem causar rebote adrenérgico severo."}]'::jsonb, '{"dopaminergic"}'),
('m55', 'Armodafinil', '{"Nuvigil"}', 'Estimulante do SNC (Eugeroico)', '{"Estimulante"}', 'Enantiômero R purificado do modafinil. Efeito principal como inibidor longo do DAT.', 'Perfil parecido com modafinil, porém pico sérico tardio conferiu maior duração durante o dia.', '{"Cefaleia forte","Palpitações","Ansiedade aguda"}', '{"Hipersensibilidade"}', '{"Oral","Comprimido"}', 'Indutor de vigília (eugeroico) que estimula o alerta cerebral central, sendo o padrão de ouro para narcolepsia e distúrbios do sono do trabalhador de turno alternado.', '[{"condition":"Sonolência Residual Associada à Depressão","evidence":"Moderado","justification":"Auxilia a debelar a anergia e o cansaço mental matinal crônico em pacientes deprimidos estabilizados."},{"condition":"Fadiga na Esclerose Múltipla","evidence":"Moderado","justification":"Melhora o rendimento motor diário e a exaustão neurológica nesses pacientes."}]'::jsonb, '[{"condition":"Narcolepsia e Hipersonia Idiopática","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Excelente indutor de vigília focada no aumento de histamina/orexina por inibição leve do DAT, sem causar rebote adrenérgico severo."}]'::jsonb, '{"dopaminergic"}'),
('m56', 'Cafeína', '{"Vivendo","Dose extra"}', 'Metilxantina', '{"Estimulante","Suplemento"}', 'Antagonista não seletivo dos receptores de adenosina (A1 e A2A), resultando em aumento secundário indireto nos disparos de dopamina e outras catecolaminas.', 'Uso off-label em TDAH leve e astenia depressiva. Doses excessivas simulam/precipitam ataques de pânico.', '{"Taquicardia","Tremores","Inquietação nervosa","Diurese farta"}', '{"Arritmias clinicamente instáveis","Transtorno de Pânico Descompensado"}', '{"Oral","Comprimido","Pó"}', 'O alvo matriz central no cerco e manejo do TDAH ou nos extremos narcolépticos/eugeroicos, resultando numa ampliação frontal direta do controle volitivo sobre distrações e limiares letárgicos basais de cansaço extremo. Usualmente associado em baixas dosagens à prática off-label astenica geriátrica se cardiopatias forem extintas.', '[{"condition":"Depressão Resistente / Apática / Geriátrica","evidence":"Moderado","justification":"Promete contornar refratariedades pela melindrosa ação combinada ativando vias mesolímbicas a exaustão."},{"condition":"Fadiga Extrema na Esclerose Múltipla ou Quimioterapia Tumoral","evidence":"Moderado","justification":"Restaura pontualmente qualidade operante mínima frente à anergia central das desmielinizações imunes e destruições quimioterápicas base de letargia aguda."},{"condition":"Transtorno de Compulsão Alimentar","evidence":"Alto","justification":"Lisdexanfetamina é estritamente aprovada nos EUA (bula) na modelagem dopaminérgica saciando refratariedades crônicas obesogênicas graves, minimizando binges mastigatórios automáticos."}]'::jsonb, '[{"condition":"TDAH (Transtorno de Déficit de Atenção e Hiperatividade)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Aumento robusto na disponibilidade cortical de dopamina e noradrenalina, otimizando o controle inibitório e foco."}]'::jsonb, '{"dopaminergic","noradrenergic"}'),
('m57', 'Atomoxetina', '{"Strattera","Atentina"}', 'Inibidor de Recaptação (Não-estimulante)', '{"Estimulante"}', 'Inibidor seletivo e altamente potente do transportador de noradrenalina (NET). Aumenta DA em regiões específicas (córtex pré-frontal) onde o NET recolhe DA.', 'É listado entre medicamentos de TDAH como "não-estimulante", possuindo atraso terapêutico semelhante aos antidepressivos (4-8 semanas).', '{"Desconforto GI","Náusea","Astenia letárgica / Sonolência atípica","Riscos hepáticos"}', '{"Uso com IMAO","Glaucoma de ângulo estreito","Feocromocitoma"}', '{"Oral","Cápsula"}', 'O alvo matriz central no cerco e manejo do TDAH ou nos extremos narcolépticos/eugeroicos, resultando numa ampliação frontal direta do controle volitivo sobre distrações e limiares letárgicos basais de cansaço extremo. Usualmente associado em baixas dosagens à prática off-label astenica geriátrica se cardiopatias forem extintas.', '[{"condition":"Depressão Resistente / Apática / Geriátrica","evidence":"Moderado","justification":"Promete contornar refratariedades pela melindrosa ação combinada ativando vias mesolímbicas a exaustão."},{"condition":"Fadiga Extrema na Esclerose Múltipla ou Quimioterapia Tumoral","evidence":"Moderado","justification":"Restaura pontualmente qualidade operante mínima frente à anergia central das desmielinizações imunes e destruições quimioterápicas base de letargia aguda."},{"condition":"Transtorno de Compulsão Alimentar","evidence":"Alto","justification":"Lisdexanfetamina é estritamente aprovada nos EUA (bula) na modelagem dopaminérgica saciando refratariedades crônicas obesogênicas graves, minimizando binges mastigatórios automáticos."}]'::jsonb, '[{"condition":"TDAH (Transtorno de Déficit de Atenção e Hiperatividade)","line":"1ª Linha","evidence":"Padrão-Ouro","justification":"Aumento robusto na disponibilidade cortical de dopamina e noradrenalina, otimizando o controle inibitório e foco."}]'::jsonb, '{"dopaminergic","noradrenergic"}')
INSERT INTO receptors (id, name, type, neurotransmitter_system, description) VALUES 
('r1', 'SERT', 'Transportador', 'Serotoninérgico', 'Transportador mediando a recaptação de serotonina na fenda.'),
('r2', 'D2', 'Receptor', 'Dopaminérgico', 'Receptor metabotrópico inibitório associado primariamente a psicose.'),
('r3', '5-HT2A', 'Receptor', 'Serotoninérgico', 'Ação pós-sináptica, seu forte bloqueio diferencia os antipsicóticos atípicos.'),
('r4', 'NET', 'Transportador', 'Noradrenérgico', 'Responsável pela reabsorção da noradrenalina para o terminal axonal.'),
('r5', 'DAT', 'Transportador', 'Dopaminérgico', 'Recolhimento da dopamina da sinapse.'),
('r6', 'H1', 'Receptor', 'Histaminérgico', 'Alvo off-target que leva a efeitos centrais de sedação e ganho de peso.'),
('r7', 'M1', 'Receptor', 'Colinérgico', 'Bloqueios sistemicos afetam ritmo salivar, intestinal e cardíaco.'),
('r8', 'Alpha-1', 'Receptor', 'Noradrenérgico', 'Bloqueio contribui para disautonomias tipo hipotensão postural e tontura.'),
('r9', '5-HT1A', 'Receptor', 'Serotoninérgico', 'Auto-receptor termostático, comumente relacionado aos atrasos terapeuticos reativos.'),
('r10', 'MAO-A', 'Enzima Alvo', 'Aminas', 'Cataboliza a serotonina, a norepinefrina, e preferencialmente a tiramina dietética.'),
('r11', 'MAO-B', 'Enzima Alvo', 'Aminas', 'Catabolização extra focada em dopamina e tiramina.'),
('r12', 'VSSC', 'Canal Iônico', 'Geral', 'Canal Na+ voltagem-dependente responsável pelo spike pontencial neuronal bruto.'),
('r13', 'GABA-A', 'Receptor', 'GABAérgico', 'Canal iônico inibitório.'),
('r14', 'MT1/MT2', 'Receptor', 'Melatoninérgico', 'Receptores mimetizando ritmo circadiano no trato SCN.'),
('r15', 'VGCC-α2δ', 'Canal Iônico', 'GABAérgico/Glutamatérgico', 'Canal de cálcio dependente de voltagem, subunidade α2δ.'),
('r16', 'µ-Opioide', 'Receptor', 'Opioide', 'Alvo mediador de analgesia e efeitos euforizantes.'),
('r17', 'κ-Opioide', 'Receptor', 'Opioide', 'Receptor envolvido em disforia, analgesia e controle comportamental.'),
('r18', 'δ-Opioide', 'Receptor', 'Opioide', 'Envolvido em efeitos antidepressivos, neuroprotetores e analgesia.'),
('r19', 'NMDA', 'Canal Iônico', 'Glutamatérgico', 'Principal canal excitatório para neuroplasticidade.'),
('r20', 'xCT', 'Enzima Alvo', 'Glutamatérgico', 'Antiporter cistina-glutamato, modulador do glutamato na fenda extrassináptica.'),
('r21', 'Sigma-1', 'Receptor', 'Glutamatérgico / Geral', 'Receptor chaperona intracelular associado à neuroproteção, plasticidade sináptica e efeitos ansiolíticos.'),
('r22', '5-HT3', 'Receptor', 'Serotoninérgico', 'Canal iônico serotoninérgico; seu antagonismo alivia náuseas e aumenta acetilcolina/noradrenalina no córtex.'),
('r23', '5-HT7', 'Receptor', 'Serotoninérgico', 'Receptor metabotrópico regulador do sono, ritmo circadiano e cognição pré-frontal.')
INSERT INTO enzymes (id, name, description, location) VALUES 
('e1', 'CYP2D6', 'Atua extensivamente em fármacos cardiovasculares e psiquiátricos. Marcada por extremo polimorfismo genético.', 'Hepático'),
('e2', 'CYP3A4', 'Enzima amplamente distribuída metabolizando metade de toda a farmacopeia global.', 'Hepático e Intestinal'),
('e3', 'CYP1A2', 'Ligada estritamente aos produtos dos compostos do tabaco aquecido, induzindo-se.', 'Hepático'),
('e4', 'CYP2C19', 'Enzima central em certos subgrupos (exóticos) metabolizadoras de es-citalopram.', 'Hepático'),
('e5', 'CYP2C9', 'Responsável em sua maioria por eliminação de AINEs e estabilizadores.', 'Hepático'),
('e6', 'UGT', 'Subfamilia das UDP-glucuronosiltransferases efetuando as fases secundárias de depuração.', 'Hepático / Renais'),
('e7', 'CYP2C8', 'Ação em algumas drogas-Z, hipoglicemiantes e taxanos.', 'Hepático'),
('e8', 'CYP2B6', 'Regula oxidação de compostos com relevância clínica como cetamina, bupropiona.', 'Hepático')
INSERT INTO pd_interactions (molecule_id, receptor_id, action_type, affinity_ki, notes, sources) VALUES 
